    arm_right_pose_b: '<g xmlns="http://www.w3.org/2000/svg" xmlns:inkscape="http://www.inkscape.org/namespaces/inkscape" xmlns:sodipodi="http://sodipodi.sourceforge.net/DTD/sodipodi-0.dtd" xmlns:svg="http://www.w3.org/2000/svg" id="g27" style="display:inline;stroke-width:2.94349;stroke-dasharray:none"><path style="display:inline;opacity:1;fill:#ffb380;fill-opacity:1;stroke:#000000;stroke-width:3;stroke-linecap:round;stroke-linejoin:round;stroke-miterlimit:0;stroke-dasharray:none;stroke-dashoffset:10.7188;stroke-opacity:1;paint-order:markers stroke fill" d="m 1837.6905,591.31911 c 5.5097,1.78691 15.8468,8.68984 17.757,12.46785 3.3395,6.60506 3.7995,9.68266 2.6436,11.87884 -0.6838,1.29921 -6.6071,9.33777 -9.8414,7.20623 -8.7288,-5.75266 -2.2222,-13.99574 -14.5676,-14.42144 -4.3184,-0.14891 -1.9479,-17.13148 4.0084,-17.13148 z" id="path24" transform="matrix(0.98116343,0,0,0.98116343,34.155693,12.809572)"/><path style="display:inline;opacity:1;fill:#1a1a1a;fill-opacity:1;stroke:#000000;stroke-width:2.94349;stroke-linecap:round;stroke-linejoin:round;stroke-miterlimit:0;stroke-dasharray:none;paint-order:markers stroke fill" d="m 1774.7164,548.94129 c -9.9866,7.93468 -12.9973,39.84921 -10.3635,46.09839 8.7617,20.78882 7.5136,21.73647 69.7663,18.57838 -2.1579,-8.96083 -2.4458,-15.83419 1.8421,-21.73646 -6.2963,-4.63189 -36.7539,-9.23519 -36.1309,-12.41937 0.9312,-4.76015 10.0324,-16.44963 3.3759,-24.91731 -6.2494,-7.94982 -20.1257,-11.28653 -28.4899,-5.60363 z" id="path25"/></g>',
