    hand_l2: '<path xmlns="http://www.w3.org/2000/svg" xmlns:inkscape="http://www.inkscape.org/namespaces/inkscape" xmlns:sodipodi="http://sodipodi.sourceforge.net/DTD/sodipodi-0.dtd" xmlns:svg="http://www.w3.org/2000/svg" id="path4" style="display:inline;fill:#ffb380;fill-opacity:1;stroke:#000000;stroke-width:3;stroke-linecap:round;stroke-linejoin:round;stroke-miterlimit:0;stroke-dasharray:none;stroke-dashoffset:10.7188;stroke-opacity:1;paint-order:markers stroke fill" d="m 1913.0053,568.96865 c -3.1588,-1.70146 -5.2127,-0.507 -9.1294,1.19735 -1.6764,0.72948 -4.7335,4.27628 -4.1831,7.47424 z m -3.2708,24.21603 c 3.3663,-1.40567 13.9951,-8.14652 14.0345,-11.97132 0.039,-3.8248 0.2473,-12.95965 -2.2979,-12.64681 -8.2783,1.01751 -9.6818,2.9792 -7.3842,6.81062 1.8631,3.10683 0.016,5.93996 -2.3097,10.14026 l -7.0278,6.55973 c 3.1877,1.18865 0.9007,0.76934 4.9851,1.10752 z" transform="matrix(0.98116343,0,0,0.98116343,34.155686,12.80957)"/>',
