/* The Blizzard of '26 — engine.js
   MVP scene build: base scene + 4 patrolling officers (2 pairs) + Doyle
   strumming in the corner. No interactivity yet (protester mode on standby).

   Coordinate system: all source art is authored in a 1660x1660 SVG space.
   We render each sprite once to an offscreen Image via SVG blob, then draw
   with canvas drawImage each frame — avoids re-parsing SVG per frame.
*/
(function () {
  'use strict';

  var SRC = 1660; // native art coordinate space (square)

  // ---- Officer sprite bounding boxes in native 1660 space (feet-anchored) ----
  // All four officer variants share the same body geometry/position.
  var OFFICER_BBOX = { x: 698, y: 706, w: 190, h: 417 };

  // ---- Doyle sub-part bounding boxes in native 1660 space ----
  var DOYLE_BBOX = {
    legs:   { x: 1777, y: 659, w: 177, h: 191 },
    shirt:  { x: 1821, y: 542, w: 30,  h: 44 },
    body:   { x: 1766, y: 534, w: 98,  h: 155 },
    armL:   { x: 1846, y: 552, w: 68,  h: 71 },
    guitar: { x: 1782, y: 544, w: 172, h: 137 },
    head:   { x: 1796, y: 493, w: 58,  h: 73 },   // includes hood width ref
    hood:   { x: 1796, y: 493, w: 48,  h: 73 },
    armR:   { x: 1760, y: 546, w: 76,  h: 89 },
    handL:  { x: 1899, y: 568, w: 25,  h: 27 }
  };
  // Full doyle character bbox (for extracting a combined standalone sprite)
  var DOYLE_FULL = { x: 1756, y: 490, w: 202, h: 364 };

  // Rotation anchors, in native 1660 space
  var DOYLE_HEAD_ANCHOR = { x: 1826, y: 554 };     // neck pivot for head nod
  var DOYLE_SHOULDER_ANCHOR = { x: 1790, y: 550 }; // shoulder pivot for arm swing

  function svgToImage(svgMarkup, viewBoxOverride) {
    var vb = viewBoxOverride || ('0 0 ' + SRC + ' ' + SRC);
    var full = '<svg xmlns="http://www.w3.org/2000/svg" width="' + SRC + '" height="' + SRC +
      '" viewBox="' + vb + '">' + svgMarkup + '</svg>';
    var blob = new Blob([full], { type: 'image/svg+xml' });
    var url = URL.createObjectURL(blob);
    var img = new Image();
    return new Promise(function (resolve) {
      img.onload = function () {
        URL.revokeObjectURL(url);
        resolve(img);
      };
      img.onerror = function () {
        URL.revokeObjectURL(url);
        resolve(null); // fail soft — missing sprite shouldn't kill the scene
      };
      img.src = url;
    });
  }

  // ---- Doyle composite sprite builder ----
  // Builds a single SVG group combining all Doyle parts at a given animation
  // state (arm pose, hand pose, head rotation), positioned so the whole
  // character's local origin is DOYLE_FULL top-left. Returns markup string.
  function buildDoyleMarkup(assets, state) {
    var armPose = state.armSwing >= 0 ? assets.doyle.arm_right_pose_a : assets.doyle.arm_right_pose_b;
    var handPose = state.handAlt ? assets.doyle.hand_l2 : assets.doyle.hand_l;

    var hx = DOYLE_HEAD_ANCHOR.x, hy = DOYLE_HEAD_ANCHOR.y;
    var sx = DOYLE_SHOULDER_ANCHOR.x, sy = DOYLE_SHOULDER_ANCHOR.y;

    // Head nod: rotate head+hood group around neck anchor
    var headGroup = '<g transform="rotate(' + state.headAngle.toFixed(2) + ' ' + hx + ' ' + hy + ')">' +
      assets.doyle.hood + assets.doyle.head + '</g>';

    // Arm swing: rotate the strum arm group around shoulder anchor
    var armGroup = '<g transform="rotate(' + state.armAngle.toFixed(2) + ' ' + sx + ' ' + sy + ')">' +
      armPose + '</g>';

    // Static parts + hand pose (hand doesn't rotate, just swaps shape)
    return '<g>' +
      assets.doyle.legs +
      assets.doyle.shirt +
      assets.doyle.body +
      assets.doyle.arm_l +
      assets.doyle.guitar +
      armGroup +
      handPose +
      headGroup +
      '</g>';
  }

  // ---- Main controller ----
  var BlizzardOf26 = {
    init: function (mount) {
      var canvas = mount.querySelector('[data-bz-canvas]');
      if (!canvas) return;
      var ctx = canvas.getContext('2d');

      var assets = window.BZ_ASSETS;
      if (!assets) {
        console.error('BlizzardOf26: BZ_ASSETS not found — assets script must load before engine.js');
        return;
      }

      var images = {
        scene: null,
        officers: {}, // agent1_forward, agent2_forward, agent1_back, agent2_back
        doyleFrames: [] // pre-rendered doyle animation frames (built lazily)
      };

      var ready = false;

      // ---- Load static images (scene + officer sprites) ----
      var loadPromises = [];

      loadPromises.push(svgToImage(assets.scene).then(function (img) { images.scene = img; }));

      ['agent1_forward', 'agent2_forward', 'agent1_back', 'agent2_back'].forEach(function (key) {
        loadPromises.push(
          svgToImage(assets.officers[key]).then(function (img) { images.officers[key] = img; })
        );
      });

      Promise.all(loadPromises).then(function () {
        ready = true;
        buildDoyleFrameCache(assets, images, function () {
          requestAnimationFrame(loop);
        });
      });

      // ---- Doyle animation frame cache ----
      // 16-frame strum cycle (arm angle oscillates, hand swaps at frame 8),
      // with head nod overlay every 32 frames. We precompute a matrix of
      // (armAngle bucket x headAngle bucket) combos actually used, rather
      // than every single frame, to keep image count sane.
      var DOYLE_STRUM_FRAMES = 16;
      var DOYLE_NOD_FRAMES = 32;

      function buildDoyleFrameCache(assets, images, cb) {
        var frames = []; // indexed by [strumFrame][nodFrame] -> Image
        var promises = [];

        for (var sF = 0; sF < DOYLE_STRUM_FRAMES; sF++) {
          frames[sF] = [];
          (function (sF) {
            for (var nF = 0; nF < DOYLE_NOD_FRAMES; nF += 4) { // sample every 4th nod-frame, interpolate visually via proximity
              (function (nF) {
                var state = computeDoyleState(sF, nF);
                var markup = buildDoyleMarkup(assets, state);
                var vb = DOYLE_FULL.x + ' ' + DOYLE_FULL.y + ' ' + DOYLE_FULL.w + ' ' + DOYLE_FULL.h;
                var p = svgToImage(markup, vb).then(function (img) {
                  frames[sF][nF] = img;
                });
                promises.push(p);
              })(nF);
            }
          })(sF);
        }

        Promise.all(promises).then(function () {
          images.doyleFrames = frames;
          cb();
        });
      }

      // Compute Doyle's arm angle, hand pose, and head angle for a given
      // strum-frame (0-15) and nod-frame (0-31).
      function computeDoyleState(strumFrame, nodFrame) {
        // Arm oscillates +/-3deg across the 16-frame strum cycle (sine-ish via triangle wave)
        var t = strumFrame / DOYLE_STRUM_FRAMES; // 0..1
        var armAngle = Math.sin(t * Math.PI * 2) * 3;
        var handAlt = strumFrame >= 8; // second half of cycle = alt hand pose

        // Head nod: neutral for first half of 32-frame cycle, nod to +6deg and back for second half
        var headAngle = 0;
        if (nodFrame >= 16 && nodFrame < 24) {
          var nt = (nodFrame - 16) / 8;
          headAngle = nt * 6;
        } else if (nodFrame >= 24 && nodFrame < 32) {
          var nt2 = (nodFrame - 24) / 8;
          headAngle = 6 - nt2 * 6;
        }

        return { armAngle: armAngle, armSwing: armAngle, handAlt: handAlt, headAngle: headAngle };
      }

      // ---- Patrol geometry ----
      // Circle centered in the open street area. Officers walk this loop;
      // pair A and pair B start at opposite phase so 2 are always "in the
      // street" (near side of circle) and 2 near/at the sidewalk (far side).
      var PATROL = {
        cx: 830,
        cy: 880,
        rx: 420,   // horizontal radius
        ry: 160,   // vertical radius (flattened ellipse for depth feel)
      };

      // Officer patrol state: angle in radians, 0 = far side (near sidewalk/back view),
      // PI = near side (toward viewer/forward view)
      var officerState = [
        { pairId: 'A', variant: 'agent1', angle: 0,               speed: 0.006 },
        { pairId: 'A', variant: 'agent1', angle: Math.PI,         speed: 0.006 },
        { pairId: 'B', variant: 'agent2', angle: Math.PI * 0.5,   speed: 0.006 },
        { pairId: 'B', variant: 'agent2', angle: Math.PI * 1.5,   speed: 0.006 }
      ];

      // ---- Render loop ----
      var frameCount = 0;
      var lastTime = null;

      function resize() {
        var rect = canvas.getBoundingClientRect();
        var dpr = window.devicePixelRatio || 1;
        // Guard against a pre-layout 0-size read (can happen on first sync
        // call before the stylesheet has applied aspect-ratio sizing).
        var w = rect.width || canvas.parentElement.clientWidth || SRC;
        canvas.width = w * dpr;
        canvas.height = w * dpr; // square stage
      }
      resize();
      window.addEventListener('resize', resize);
      // Re-run once more after layout settles, in case the first call
      // landed before CSS aspect-ratio sizing took effect.
      requestAnimationFrame(resize);

      function drawScene() {
        var w = canvas.width, h = canvas.height;
        var scale = w / SRC;

        ctx.setTransform(scale, 0, 0, scale, 0, 0);
        ctx.clearRect(0, 0, SRC, SRC);

        if (images.scene) {
          ctx.drawImage(images.scene, 0, 0, SRC, SRC);
        }

        // ---- Draw officers ----
        officerState.forEach(function (o) {
          var pos = patrolPosition(o.angle);
          var facingForward = Math.sin(o.angle) > 0; // near half of loop = facing viewer
          var spriteKey = o.variant + (facingForward ? '_forward' : '_back');
          var img = images.officers[spriteKey];
          if (!img) return;

          // Depth scale: slightly smaller near the far/back side of the loop
          var depthT = (Math.cos(o.angle) + 1) / 2; // 0 at near(front), 1 at far(back) roughly
          var scaleFactor = 1 - depthT * 0.18;

          var footX = pos.x;
          var footY = pos.y;
          var drawW = OFFICER_BBOX.w * scaleFactor;
          var drawH = OFFICER_BBOX.h * scaleFactor;
          var drawX = footX - drawW / 2;
          var drawY = footY - drawH;

          ctx.drawImage(img, OFFICER_BBOX.x, OFFICER_BBOX.y, OFFICER_BBOX.w, OFFICER_BBOX.h,
            drawX, drawY, drawW, drawH);
        });

        // ---- Draw Doyle ----
        var strumFrame = frameCount % DOYLE_STRUM_FRAMES;
        var nodFrame = frameCount % DOYLE_NOD_FRAMES;
        var nodFrameSnapped = Math.floor(nodFrame / 4) * 4;
        var frameRow = images.doyleFrames[strumFrame];
        var doyleImg = frameRow ? frameRow[nodFrameSnapped] : null;

        if (doyleImg) {
          // Position Doyle in bottom-left corner of the scene
          var doyleDrawW = DOYLE_FULL.w * 0.62;
          var doyleDrawH = DOYLE_FULL.h * 0.62;
          var doyleX = 40;
          var doyleY = SRC - doyleDrawH - 30;
          ctx.drawImage(doyleImg, doyleX, doyleY, doyleDrawW, doyleDrawH);
        }

        // ---- "COMING SOON" text, bottom-left toward center, fading right ----
        drawComingSoon(ctx);
      }

      function patrolPosition(angle) {
        return {
          x: PATROL.cx + Math.cos(angle) * PATROL.rx,
          y: PATROL.cy + Math.sin(angle) * PATROL.ry
        };
      }

      function drawComingSoon(ctx) {
        var text = 'COMING SOON';
        var baseY = SRC - 45;
        var startX = SRC * 0.5;
        var fontSize = 46;

        ctx.save();
        ctx.font = '700 ' + fontSize + 'px "Special Elite", "Archivo Narrow", system-ui, sans-serif';
        ctx.textBaseline = 'alphabetic';

        // Measure to right-align the fade start at center, extending left
        var metrics = ctx.measureText(text);
        var textW = metrics.width;
        var endX = startX; // text ends at center, extends left
        var beginX = endX - textW;

        var grad = ctx.createLinearGradient(beginX, 0, endX, 0);
        grad.addColorStop(0, 'rgba(20,23,28,0.92)');
        grad.addColorStop(1, 'rgba(20,23,28,0)');

        // background strip behind text for legibility
        ctx.fillStyle = grad;
        ctx.fillRect(0, baseY - fontSize, endX + 20, fontSize * 1.6);

        ctx.fillStyle = '#e0b23e';
        ctx.textAlign = 'left';
        ctx.fillText(text, beginX, baseY);
        ctx.restore();
      }

      function loop(ts) {
        if (!ready) {
          requestAnimationFrame(loop);
          return;
        }
        if (lastTime === null) lastTime = ts;
        var dt = ts - lastTime;
        lastTime = ts;

        // Advance officer patrol angles
        officerState.forEach(function (o) {
          o.angle += o.speed;
          if (o.angle > Math.PI * 2) o.angle -= Math.PI * 2;
        });

        // Advance animation frame counter at a fixed cadence (~ every 60ms per frame step)
        if (dt > 0) {
          frameCount += 1;
        }

        drawScene();
        requestAnimationFrame(loop);
      }
    }
  };

  window.BlizzardOf26 = BlizzardOf26;
})();



/* The Blizzard of '26 — loader.js (bundled)
   Single-file embed: styles + assets + engine + bootstrap.
   Follows Casey Minigame Contract v1 pattern (portable, self-contained). */
(function () {
  'use strict';

  window.__BZ_STYLES__ = `/* The Blizzard of '26 — styles.css
   Canvas-based game (per Contract §10 D6): --gm-* tokens style the DOM chrome
   only. The canvas itself is drawn in JS and doesn't read these tokens (no
   HUD chrome exists yet in this MVP scene-only build). */

/* 2a. DEFAULTS — themeable token fallbacks */
@property --cms-primary { syntax: '<color>'; inherits: true; initial-value: #e0b23e; }
@property --cms-surface { syntax: '<color>'; inherits: true; initial-value: #14171c; }
@property --cms-ink     { syntax: '<color>'; inherits: true; initial-value: #d7dde4; }
@property --cms-accent  { syntax: '<color>'; inherits: true; initial-value: #6699ff; }

/* 2b. CMS THEME BLOCK — empty by default, Webflow can bind later */
.bz-root {
  --cms-primary: ;
  --cms-surface: ;
  --cms-ink: ;
  --cms-accent: ;
}

/* 2c. SHELL tokens */
.bz-root {
  --gm-primary: var(--cms-primary);
  --gm-surface: var(--cms-surface);
  --gm-ink: var(--cms-ink);
  --gm-accent: var(--cms-accent);

  --gm-font-display: var(--_typography---font-styles--heading, 'Special Elite', 'Archivo Narrow', system-ui, sans-serif);
  --gm-font-body: var(--_typography---font-styles--body, 'Spline Sans Mono', ui-monospace, monospace);

  display: block;
  width: 100%;
  background: var(--gm-surface);
  border-radius: 2px;
  overflow: hidden;
  box-sizing: border-box;
  font-family: var(--gm-font-body);
  color: var(--gm-ink);
}

.bz-root *,
.bz-root *::before,
.bz-root *::after {
  box-sizing: border-box;
}

/* 2d. ENGINE — .bz- namespace */
.bz-stage-wrap {
  position: relative;
  width: 100%;
  aspect-ratio: 1 / 1;
  background: #6699ff;
  overflow: hidden;
}

.bz-canvas {
  display: block;
  width: 100%;
  height: 100%;
}
`;

  function boot() {
    var mounts = document.querySelectorAll('[data-blizzard-of-26]');
    if (!mounts.length) return;

    mounts.forEach(function (mount) {
      if (mount.dataset.bzReady) return;
      mount.dataset.bzReady = '1';

      if (!document.getElementById('bz-styles')) {
        var styleTag = document.createElement('style');
        styleTag.id = 'bz-styles';
        styleTag.textContent = window.__BZ_STYLES__;
        document.head.appendChild(styleTag);
      }

      mount.innerHTML =
        '<div class="gm-root bz-root">' +
        '  <div class="bz-stage-wrap">' +
        '    <canvas class="bz-canvas" data-bz-canvas></canvas>' +
        '  </div>' +
        '</div>';

      if (window.BlizzardOf26 && typeof window.BlizzardOf26.init === 'function') {
        window.BlizzardOf26.init(mount);
      }
    });
  }

  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', boot);
  } else {
    boot();
  }
})();
